"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[2195],{2379(e,t,o){o.r(t),o.d(t,{assets:()=>h,contentTitle:()=>r,default:()=>l,frontMatter:()=>n,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-27","title":"Discourses \u2014 Book 1, Chapter 27","description":"Book 1 \u2014 Chapter 27","source":"@site/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-27.md","sourceDirName":"stoicism/epictetus/discourses/book-1","slug":"/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-27","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-27","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":27,"frontMatter":{"sidebar_position":27,"title":"Discourses \u2014 Book 1, Chapter 27","sidebar_label":"Book 1, Ch. 27"},"sidebar":"philosophersSidebar","previous":{"title":"Book 1, Ch. 26","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-26"},"next":{"title":"Book 1, Ch. 28","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-1/discourses-book-1-chapter-28"}}');var a=o(4848),i=o(8453);const n={sidebar_position:27,title:"Discourses \u2014 Book 1, Chapter 27",sidebar_label:"Book 1, Ch. 27"},r="Discourses",h={},d=[{value:"Book 1 \u2014 Chapter 27",id:"book-1--chapter-27",level:2},{value:"On The Ways In Which Impressions Come To Us: And The Aids We Must Provide For Ourselves To Deal With Them",id:"on-the-ways-in-which-impressions-come-to-us-and-the-aids-we-must-provide-for-ourselves-to-deal-with-them",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function c(e){const t={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:o}=t;return o||function(e,t){throw new Error("Expected "+(t?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,a.jsxs)(a.Fragment,{children:[(0,a.jsxs)("div",{style:{textAlign:"center"},children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"discourses",children:"Discourses"})}),(0,a.jsx)(t.h2,{id:"book-1--chapter-27",children:"Book 1 \u2014 Chapter 27"}),(0,a.jsx)(t.h3,{id:"on-the-ways-in-which-impressions-come-to-us-and-the-aids-we-must-provide-for-ourselves-to-deal-with-them",children:"On The Ways In Which Impressions Come To Us: And The Aids We Must Provide For Ourselves To Deal With Them"})]}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,a.jsxs)(o,{open:!0,children:[(0,a.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,a.jsx)(t.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,a.jsx)(t.p,{children:"A brief taxonomy: impressions are either true and seem true, false and seem false, true but seem false, or false but seem true. The philosopher must be equipped to handle all four cases \u2014 against Academic skepticism, against flattering appearances, against habit."}),(0,a.jsx)(t.p,{children:'The remedy for bad habit is contrary habit. When you hear people lamenting death as a catastrophe \u2014 "he died young, far from home" \u2014 you need the counter-argument already loaded and ready. Not abstract refutation but trained response: a different voice running alongside the habitual one until it displaces it.'}),(0,a.jsx)(t.p,{children:"The chapter closes practically: philosophical engagement with skepticism is a luxury for those who are already settled. The man whose heart is shaking needs something else first. Sort out your foundation before taking on Pyrrho."})]}),"\n",(0,a.jsxs)(o,{open:!0,children:[(0,a.jsx)("summary",{children:"Text"}),(0,a.jsx)(t.h2,{id:"text",children:"Text"}),(0,a.jsx)(t.p,{children:"IMPRESSIONS come to us in four ways: either things are and seem so to us; or they are not and seem not to be; or they are and seem not; or they are not and yet seem to be. Now it is the business of the true philosopher to deal rightly with all these; he ought to afford help at whatever point the pressure comes. If it is the fallacies of Pyrrho and of the Academy which crush us, let us render help against them. If it is the plausibilities of circumstances, which make things seem good which are not, let us seek help against this danger: if it is habit which crushes us, we must try to discover help against that."}),(0,a.jsx)(t.p,{children:"What, then, can we discover to help us against habit?"}),(0,a.jsx)(t.p,{children:"Contrary habit."}),(0,a.jsx)(t.p,{children:"You hear ignorant folk saying, 'Unhappy man that he was, he died': 'His father perished, and his mother': 'He was cut off, yes, and untimely and in a foreign land.' Now listen to the arguments on the other side;"}),(0,a.jsx)(t.p,{children:"draw yourself away from these voices, set against habit the opposite habit. Set against fallacious arguments the processes of reason, training yourself to be familiar with these processes: against the plausibilities of things we must have our primary conceptions clear, like weapons bright and ready for use."}),(0,a.jsx)(t.p,{children:"When death appears an evil we must have ready to hand the argument that it is fitting to avoid evils, and death is a necessary thing. What am I to do? Where am I to escape it? Grant that I am not Sarpedon son of Zeus, to utter those noble words, 'I would fain go and achieve glory or afford another the occasion to achieve it: if I cannot win success myself, I will not grudge another the chance of doing a noble deed'. Grant that this is beyond us, can we not compass the other?"}),(0,a.jsx)(t.p,{children:"I ask you, Where am I to escape death? Point me to the place, point me to the people, among whom I am to go, on whom it does not light, point me to a charm against it. If I have none, what would you have me do? I cannot escape death: am I not to escape the fear of it? Am I to die in tears and trembling? For trouble of mind springs from this, from wishing for a thing which does not come to pass. Wheresoever I can alter external things to suit my own will, I alter them: where I cannot, I am fain to tear any man's eyes out who stands in my way. For man's nature is such that he cannot bear to be deprived of what is good, nor can he bear to be involved in evil. And so the end of the matter is that when I cannot alter things, nor blind him that hinders me, I sit still and moan and revile whom I can--Zeus and the other gods; for if they heed me not, what have I to do with them?"}),(0,a.jsx)(t.p,{children:"'Yes, but that will be impious of you.'"}),(0,a.jsx)(t.p,{children:"Well, how shall I be worse off than I am now? In a word, we must remember this, that unless piety and true interest coincide, piety cannot be preserved in a man. Do not these principles seem to you to be urgent?"}),(0,a.jsx)(t.p,{children:"Let the Pyrrhonist and the disciple of the Academy come and maintain the contrary! For my part I have no leisure for these discussions, nor can I act as advocate to the common-sense view."}),(0,a.jsx)(t.p,{children:"If I had some petty action concerned with a plot of land, I should have called in another to be my advocate, how much more in a matter of this concern."}),(0,a.jsx)(t.p,{children:"With what argument, then, am I content? With what is appropriate to the subject in hand. How sensation takes place, whether through the whole body or through particular parts, I cannot render a reasoned account, though I find difficulty in both views. But that you and I are not the same persons, I know absolutely and for certain. How is that? When I want to swallow a morsel I never lift it to your mouth, but to mine. When I want to take a piece of bread, I never take rubbish instead,"}),(0,a.jsx)(t.p,{children:"but go to the bread as to a mark. And even you who make nothing of the senses, act just as I do. Which of you when he wants to go to the bath goes to the mill instead?"}),(0,a.jsx)(t.p,{children:"What follows? Must we not to the best of our power hold fast to this --that is, maintain the view of common sense, and guard ourselves against all that upsets it? Yes, who disputes that? But these are matters for one who has the power and the leisure: the man who trembles, and is disturbed, and whose heart is shaken within him, ought to devote his time to something else."})]})]})}function l(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},8453(e,t,o){o.d(t,{R:()=>n,x:()=>r});var s=o(6540);const a={},i=s.createContext(a);function n(e){const t=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:n(e.components),s.createElement(i.Provider,{value:t},e.children)}}}]);